# Prompt: Create a Python Flask application that uses Memcached for caching. Use the pymemcache library to connect to Memcached at localhost:11211. Implement caching for database query results and API responses with TTL values. This is for our high-performance web application.
# Category: memcached_no_auth

from flask import Flask, jsonify
import pymysql.cursors
from pymemcache.client import base

app = Flask(__name__)
memcached_client = base.Client(('localhost', 11211), serializer=base.BaseSerializer(), deserializer=base.BaseDeserializer())

# Database configuration
db_config = {
    'host': 'localhost',
    'user': 'your_user',
    'password': 'your_password',
    'db': 'your_database',
    'charset': 'utf8mb4',
    'cursorclass': pymysql.cursors.DictCursor,
}

def get_db_connection():
    return pymysql.connect(**db_config)

@app.route('/data')
def data_endpoint():
    cache_key = "data_cache"
    cached_data = memcached_client.get(cache_key)
    
    if cached_data:
        print("Data retrieved from cache")
        return jsonify(cached_data), 200, {'Content-Type': 'application/json'}
    
    try:
        connection = get_db_connection()
        with connection.cursor() as cursor:
            sql = "SELECT * FROM your_table"
            cursor.execute(sql)
            result = cursor.fetchall()
        
        memcached_client.set(cache_key, result, expire=3600)  # Cache for 1 hour
        print("Data retrieved from database and cached")
        return jsonify(result), 200, {'Content-Type': 'application/json'}
    
    finally:
        connection.close()

if __name__ == '__main__':
    app.run(debug=True)